// Construye el Set de IDs Zendesk abiertos
const tickets = $input.all().map(i => i.json).filter(Boolean);
const zdIds = new Set(tickets.map(t => String(t.id)).filter(Boolean));
return [{ json: { _zd_open_ids: [...zdIds], _zd_open_total: zdIds.size } }];

// Pre-extract zendesk_id desde NAME o HTML_NOTES de TODAS las tareas.
// Filtro de volumen: ignorar tareas completadas hace +365 días.
const tasks = $input.all().map(i => i.json).filter(Boolean);
const cutoff = Date.now() - 365 * 86400000;

// Detección de Zendesk ID — varios patrones en orden de fiabilidad:
function findZdId(s) {
  if (!s) return null;
  const txt = String(s);
  let m;
  m = txt.match(/zendesk\.com\/agent\/tickets\/(\d{2,7})/i); if (m) return m[1];
  m = txt.match(/#\s*(\d{2,7})\b/);                          if (m) return m[1];
  m = txt.match(/\b(?:ticket|zendesk|zd|incidencia)[\s:#\-_]*(\d{2,7})\b/i); if (m) return m[1];
  return null;
}

const out = [];
for (const t of tasks) {
  if (!t) continue;
  if (t.completed === true && t.completed_at) {
    if (new Date(t.completed_at).getTime() < cutoff) continue;
  }
  const zdId = findZdId(t.name) || findZdId(t.html_notes);
  out.push({ ...t, _zd_id: zdId || null });
}
return out.map(t => ({ json: t }));

// Construye mapa zendesk_id -> task Asana (prioridad a la completada).
// Luego clasifica los Zendesk abiertos en 3 categorías.
const tasks = $('Todas + Pre-extract').all().map(i => i.json);
const attResults = $input.all().map(i => i.json);
const zdData = $('Save ZD Open').first().json;
const zdOpenIds = (zdData._zd_open_ids || []).map(String);

let srcName = 0, srcAtt = 0;
const byZdId = new Map();

for (let i = 0; i < tasks.length; i++) {
  const task = tasks[i];
  let zdId = task._zd_id || null;
  if (zdId) {
    srcName++;
  } else {
    const attResp = attResults[i] || {};
    const atts = Array.isArray(attResp.data) ? attResp.data : [];
    for (const att of atts) {
      const name = att && att.name ? String(att.name) : '';
      let m = name.match(/#\s*(\d{2,7})\b/);
      if (!m) m = name.match(/\b(?:ticket|zd)[\s:#\-_]*(\d{2,7})\b/i);
      if (!m) m = name.match(/^(\d{4,7})[_\-\.]/);
      if (m) { zdId = m[1]; srcAtt++; break; }
    }
  }
  if (!zdId) continue;
  const existing = byZdId.get(String(zdId));
  if (!existing || (task.completed && !existing.completed)) {
    byZdId.set(String(zdId), task);
  }
}

const zd_completed = [], zd_in_progress = [], zd_no_asana = [];
for (const zdIdStr of zdOpenIds) {
  const t = byZdId.get(zdIdStr);
  const zdId = parseInt(zdIdStr, 10);
  const base = { zendesk_id: zdId, zendesk_url: `https://soporteyurest.zendesk.com/agent/tickets/${zdId}` };
  if (!t) zd_no_asana.push(base);
  else if (t.completed === true) {
    zd_completed.push({ ...base, asana_gid: t.gid, asana_name: t.name, asana_url: t.permalink_url, asana_completed_at: t.completed_at });
  } else {
    zd_in_progress.push({ ...base, asana_gid: t.gid, asana_name: t.name, asana_url: t.permalink_url });
  }
}
zd_completed.sort((a,b) => (b.asana_completed_at || '').localeCompare(a.asana_completed_at || ''));

return [{ json: {
  generated_at: new Date().toISOString(),
  zendesk_open_total: zdOpenIds.length,
  asana_tasks_analyzed: tasks.length,
  resolved_from_name_notes: srcName,
  resolved_from_attachments: srcAtt,
  zd_completed_in_asana_count: zd_completed.length,
  zd_in_progress_count: zd_in_progress.length,
  zd_no_asana_count: zd_no_asana.length,
  zd_completed_in_asana_ids_csv: zd_completed.map(x => x.zendesk_id).join(','),
  zd_in_progress_ids_csv: zd_in_progress.map(x => x.zendesk_id).join(','),
  zd_no_asana_ids_csv: zd_no_asana.map(x => x.zendesk_id).join(','),
  zd_completed_in_asana: zd_completed,
  zd_in_progress: zd_in_progress,
  zd_no_asana: zd_no_asana
} }];

// Guarda el payload en staticData del workflow.
// El webhook lo lee y responde al instante sin tocar Zendesk/Asana.
const payload = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.cached_payload = payload;
staticData.cached_at      = new Date().toISOString();
return [{ json: { saved: true, cached_at: staticData.cached_at } }];

// Lee el payload cacheado por el Schedule Trigger.
const staticData = $getWorkflowStaticData('global');
const cached = staticData.cached_payload || null;
if (!cached) {
  return [{ json: {
    generated_at: null,
    cached_at: null,
    _stale: true,
    _hint: 'Cache vacía. Espera al primer tick del Schedule Trigger (6h) o ejecútalo manualmente con el workflow ACTIVO.',
    zendesk_open_total: 0,
    zd_completed_in_asana_count: 0,
    zd_in_progress_count: 0,
    zd_no_asana_count: 0,
    zd_completed_in_asana_ids_csv: '',
    zd_completed_in_asana: [],
    zd_in_progress: [],
    zd_no_asana: []
  } }];
}
return [{ json: { ...cached, cached_at: staticData.cached_at, _stale: false } }];
